                        <TwitterIcon size={20} />
                    </a>
                    <button className="hamburger" onClick={() => setMenuOpen(o => !o)} aria-label="menu">
                        <span /><span /><span />
                    </button>
                </div>
            </div>
        </nav>
    )
}

import { useState } from 'react'
import { ethers } from 'ethers'
import { ShieldIcon } from '../components/icons'
import './ApprovalRevoker.css'

const RPC_URL = 'https://data-seed-prebsc-1-s1.binance.org:8545'

// Minimal ERC20 ABI for allowance/approve
const ERC20_ABI = [
    "function allowance(address owner, address spender) view returns (uint256)",
    "function approve(address spender, uint256 amount) returns (bool)",
    "function symbol() view returns (string)",
    "function decimals() view returns (uint8)"
]

// Common token addresses on BSC Testnet (for demo)
const KNOWN_TOKENS = {
    '0x337610d27c682E347C9cD60BD4b3b107C9d34dDd': 'USDT',
    '0xeD24FC36d5Ee211Ea25A80239Fb8C4Cfd80f12Ee': 'BUSD',
}

export default function ApprovalRevoker() {
    const [privateKey, setPrivateKey] = useState('')
    const [loading, setLoading] = useState(false)
    const [approvals, setApprovals] = useState([])
    const [error, setError] = useState('')
    const [scanned, setScanned] = useState(false)
    const [revokingId, setRevokingId] = useState(null)

    async function scanApprovals() {
        setError('')
        setApprovals([])
        setScanned(false)

        let wallet
        try {
            const provider = new ethers.JsonRpcProvider(RPC_URL)
            wallet = new ethers.Wallet(privateKey.trim(), provider)
        } catch {
            setError('Invalid private key.')
            return
        }

        setLoading(true)
        try {
            // In a real production app, we would query an Indexer API (like moralis, covalent, or an explorer)
            // to find all Approval event logs for this owner address up to the current block.
            // Since we are limited to an RPC here with no native log indexer easily available without 
            // timing out the response, we will simulate the finding by checking hardcoded common tokens.
            // When migrating to Aster L1, swap this out for the Aster Block Explorer API Endpoint.

            const foundApprovals = []

            for (const [tokenAddr, symbol] of Object.entries(KNOWN_TOKENS)) {
                const contract = new ethers.Contract(tokenAddr, ERC20_ABI, wallet.provider)

                // We're checking a hardcoded common spender (like PancakeSwap / Uniswap router)
                // In production with an Explorer API, it would give us every unique spender directly.
                const commonSpender = '0x9Ac64Cc6e4415144C455BD8E4837Fea55603e5c3' // PancakeSwap Testnet Router

                try {
                    const allowance = await contract.allowance(wallet.address, commonSpender)

                    if (allowance > 0n) {
                        foundApprovals.push({
                            id: `${tokenAddr}-${commonSpender}`,
                            tokenAddress: tokenAddr,
                            tokenSymbol: symbol,
                            spender: commonSpender,
                            amount: allowance > ethers.parseUnits('1000000', 18) ? 'Infinite' : ethers.formatUnits(allowance, 18),
                            rawAmount: allowance,
                            contract: new ethers.Contract(tokenAddr, ERC20_ABI, wallet)
                        })
                    }
                } catch (e) {
                    // Ignore tokens that error out (might not exist on this specific network)
                }
            }

            // MOCK DATA for Demo purposes since testnet RPC won't easily yield actual historical logs
            if (foundApprovals.length === 0) {
                foundApprovals.push({
                    id: 'mock-1',
                    tokenAddress: '0x123...abc',
                    tokenSymbol: 'SHIB',
                    spender: '0xUniswapRouter...',
                    amount: 'Infinite',
                    rawAmount: 0n,
                    isMock: true
                })
                foundApprovals.push({
                    id: 'mock-2',
                    tokenAddress: '0x456...def',
                    tokenSymbol: 'PEPE',
                    spender: '0xSketchyDapp...',
                    amount: 'Infinite',
                    rawAmount: 0n,
                    isMock: true
                })
            }

            setApprovals(foundApprovals)
            setScanned(true)
        } catch (e) {
            setError('Failed to scan approvals. Node might be rate-limiting.')
        } finally {
            setLoading(false)
        }
    }

    async function revokeApproval(approval) {
        if (approval.isMock) {
            // Simulate revoking for the mock data
            setRevokingId(approval.id)
            setTimeout(() => {
                setApprovals(prev => prev.filter(a => a.id !== approval.id))
                setRevokingId(null)
            }, 1500)
            return
        }

        setRevokingId(approval.id)
        try {
            // Explicity approve(spender, 0)
            const tx = await approval.contract.approve(approval.spender, 0n)
            await tx.wait()

            // Remove from list
            setApprovals(prev => prev.filter(a => a.id !== approval.id))
        } catch (e) {
            alert(`Failed to revoke: ${e.message}`)
        } finally {
            setRevokingId(null)
        }
    }

    return (
        <div className="page fade-up">
            <h1 className="page-title">Token Approval Revoker</h1>
            <p className="page-subtitle">Scan your wallet for unlimited token approvals given to sketchy smart contracts and revoke them instantly.</p>

            <div className="alert alert-warning" style={{ marginBottom: 24, alignItems: 'flex-start' }}>
                <ShieldIcon style={{ width: 22, height: 22, flexShrink: 0, marginTop: 2, stroke: '#fcd34d' }} />
                <div>
                    <strong>Stay Safu:</strong> If a dapp gets hacked, your wallet is safe as long as they don't have "Infinite Approval" to spend your tokens. Scan to find your risks.
                </div>
            </div>

            <div className="card">
                <div className="input-group">
                    <label className="input-label">Wallet Private Key</label>
                    <input
                        type="password"
                        className="input"
                        placeholder="Paste private key to scan..."
                        value={privateKey}
                        onChange={e => setPrivateKey(e.target.value)}
                        spellCheck={false}
                    />
                </div>

                {error && <div className="alert alert-warning" style={{ marginBottom: 16 }}>ÔÜá´©Å {error}</div>}

                <button
                    className="btn btn-primary"
                    onClick={scanApprovals}
                    disabled={loading || !privateKey}
                    style={{ width: '100%', height: 50 }}
                >
                    {loading ? <><span className="loader" /> Scanning Blockchain...</> : <><ShieldIcon color="black" style={{ width: 18, height: 18 }} /> Scan Approvals</>}
                </button>
            </div>

            {scanned && (
                <div className="card fade-up" style={{ marginTop: 24 }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
                        <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem' }}>
                            Active Allowances ({approvals.length})
                        </h3>
                        {approvals.length > 0 && (
                            <button className="btn btn-ghost" style={{ color: '#ef4444' }}>
                                Revoke All (x{approvals.length})
                            </button>
                        )}
                    </div>

                    {approvals.length === 0 ? (
                        <div style={{ textAlign: 'center', padding: '40px 0', color: 'var(--text-secondary)' }}>
                            <ShieldIcon color="#10b981" style={{ width: 48, height: 48, marginBottom: 16, opacity: 0.8 }} />
                            <p>Your wallet is perfectly clean.</p>
                            <p style={{ fontSize: '0.9rem', opacity: 0.7 }}>No active token approvals found.</p>
                        </div>
                    ) : (
                        <div className="approvals-list" style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
                            {approvals.map(app => (
                                <div key={app.id} className="approval-item card" style={{ padding: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: 'rgba(255,255,255,0.02)' }}>
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                                            <span style={{ fontWeight: 'bold', fontSize: '1.1rem' }}>{app.tokenSymbol}</span>
                                            <span className="badge badge-cyan" style={{ fontSize: '0.75rem' }}>{app.amount} Allowance</span>
                                            {app.isMock && <span className="badge badge-purple" style={{ fontSize: '0.75rem' }}>MOCK DATA</span>}
                                        </div>
                                        <div style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', fontFamily: 'var(--font-mono)' }}>
                                            Spender: {app.spender}
                                        </div>
                                    </div>

                                    <button
                                        className="btn btn-secondary"
                                        style={{ border: '1px solid rgba(239, 68, 68, 0.3)', color: '#ef4444', minWidth: 100 }}
                                        onClick={() => revokeApproval(app)}
                                        disabled={revokingId === app.id}
                                    >
                                        {revokingId === app.id ? <span className="loader" style={{ width: 14, height: 14, borderColor: 'rgba(239, 68, 68, 0.2)', borderTopColor: '#ef4444' }} /> : 'Revoke'}
                                    </button>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            )}
        </div>
    )
}

import { useState } from 'react'
import { ethers } from 'ethers'
import { SweeperIcon } from '../components/icons'
import './DustSweeper.css'

const RPC_URL = 'https://data-seed-prebsc-1-s1.binance.org:8545'

export default function DustSweeper() {
    const [privateKeys, setPrivateKeys] = useState('')
    const [destination, setDestination] = useState('')
    const [loading, setLoading] = useState(false)
    const [results, setResults] = useState([])
    const [error, setError] = useState('')

    async function sweepDust() {
        setError('')
        setResults([])

        const dest = destination.trim()
        if (!ethers.isAddress(dest)) {
            setError('Invalid destination address.')
            return
        }

        const keys = privateKeys.split('\n').map(k => k.trim()).filter(Boolean)
        if (keys.length === 0) {
            setError('Please enter at least one private key.')
            return
        }

        setLoading(true)
        const newResults = []
        const provider = new ethers.JsonRpcProvider(RPC_URL)

        try {
            for (const pk of keys) {
                let wallet
                try {
                    wallet = new ethers.Wallet(pk, provider)
                } catch {
                    newResults.push({ key: pk.slice(0, 10) + '...', status: 'error', message: 'Invalid private key' })
                    continue
                }

                try {
                    const balance = await provider.getBalance(wallet.address)
                    if (balance === 0n) {
                        newResults.push({ address: wallet.address, status: 'skipped', message: '0 balance' })
                        continue
                    }

                    // Estimate gas for a simple transfer
                    const txParams = { to: dest, value: balance } // Temp value to get gas
                    const gasLimit = 21000n // Standard ETH transfer
                    const feeData = await provider.getFeeData()
                    const gasPrice = feeData.gasPrice || (await provider.getBlock('latest')).baseFeePerGas

                    const gasCost = gasLimit * gasPrice

                    if (balance <= gasCost) {
                        newResults.push({
                            address: wallet.address,
                            status: 'skipped',
                            message: `Balance too low to cover gas (${ethers.formatEther(balance)} ETH)`
                        })
                        continue
                    }

                    // Subtract gas cost from balance to send the maximum possible
                    const amountToSend = balance - gasCost

                    const tx = await wallet.sendTransaction({
                        to: dest,
                        value: amountToSend,
                        gasLimit: gasLimit,
                        gasPrice: gasPrice
                    })

                    newResults.push({
                        address: wallet.address,
                        status: 'success',
                        message: `Sent ${ethers.formatEther(amountToSend)} ETH`,
                        hash: tx.hash
                    })
                } catch (e) {
                    newResults.push({ address: wallet.address, status: 'error', message: e.message || 'Transaction failed' })
                }
            }
            setResults(newResults)
        } catch (e) {
            setError('An unexpected error occurred during sweeping.')
        } finally {
            setLoading(false)
        }
    }

    return (
        <div className="page fade-up">
            <h1 className="page-title">Dust Sweeper</h1>
            <p className="page-subtitle">Got 10 burner wallets with $1 of ETH left in each? Sweep them all to a single cold wallet in one click.</p>

            <div className="alert alert-warning" style={{ marginBottom: 24, alignItems: 'flex-start' }}>
                <SweeperIcon style={{ width: 22, height: 22, flexShrink: 0, marginTop: 2, stroke: '#fcd34d' }} />
                <div>
                    <strong>Secure & Local:</strong> Your private keys never leave your browser. Transactions are signed locally and broadcasted directly to the RPC.
                </div>
            </div>

            <div className="card">
                <div className="input-group">
                    <label className="input-label">Destination Address</label>
                    <input
                        className="input"
                        placeholder="0x... (Where to send the funds)"
                        value={destination}
                        onChange={e => setDestination(e.target.value)}
                        spellCheck={false}
                    />
                </div>

                <div className="input-group">
                    <label className="input-label">Burner Private Keys (One per line)</label>
                    <textarea
                        className="input"
                        placeholder="0xabc123...&#10;0xdef456...&#10;..."
                        value={privateKeys}
                        onChange={e => setPrivateKeys(e.target.value)}
                        spellCheck={false}
                        style={{ minHeight: 120, resize: 'vertical' }}
                    />
                </div>

                {error && <div className="alert alert-warning" style={{ marginBottom: 16 }}>ÔÜá´©Å {error}</div>}

                <button
                    className="btn btn-primary"
                    onClick={sweepDust}
                    disabled={loading || !destination || !privateKeys}
                    style={{ width: '100%' }}
                >
                    {loading ? <><span className="loader" /> Sweeping Dust...</> : <><SweeperIcon color="black" style={{ width: 18, height: 18 }} /> Sweep All Dust</>}
                </button>
            </div>

            {results.length > 0 && (
                <div className="card fade-up" style={{ marginTop: 24 }}>
                    <h3 style={{ marginBottom: 16, fontFamily: 'var(--font-display)', fontSize: '1rem' }}>­ƒº╣ Sweep Results</h3>
                    <div className="results-list" style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                        {results.map((r, i) => (
                            <div key={i} className={`result-item ${r.status}`} style={{
                                padding: '12px',
                                borderRadius: '8px',
                                display: 'flex',
                                justifyContent: 'space-between',
                                alignItems: 'center',
                                background: r.status === 'success' ? 'rgba(16, 185, 129, 0.1)' :
                                    r.status === 'error' ? 'rgba(239, 68, 68, 0.1)' : 'rgba(255, 255, 255, 0.05)',
                                border: `1px solid ${r.status === 'success' ? 'rgba(16, 185, 129, 0.2)' :
                                    r.status === 'error' ? 'rgba(239, 68, 68, 0.2)' : 'rgba(255, 255, 255, 0.1)'}`
                            }}>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                                    <span style={{ fontFamily: 'var(--font-mono)', fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                                        {r.address ? `${r.address.slice(0, 6)}...${r.address.slice(-4)}` : r.key}
                                    </span>
                                    <span style={{
                                        fontSize: '0.9rem',
                                        color: r.status === 'success' ? '#10b981' : r.status === 'error' ? '#ef4444' : 'var(--text-secondary)'
                                    }}>
                                        {r.message}
                                    </span>
                                </div>
                                {r.hash && (
                                    <a
                                        href={`https://testnet.bscscan.com/tx/${r.hash}`}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        style={{ fontSize: '0.85rem', color: 'var(--brand)', textDecoration: 'none' }}
                                    >
                                        View Tx Ôåù
                                    </a>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    )
}

